public partial class BaseTest
{
        public void testNumberToBE()
        {
            var exchange = new ccxt.Exchange(new Dictionary<string, object>() {
                { "id", "sampleexchange" },
            });
            Assert(isEqual(exchange.parseNumber(null), null), "GO skip trick");
            Assert("GO_SKIP_START");
            // 1234567890 (decimal) = 0x499602D2 (hex)
            // BE: 00 00 00 00 49 96 02 D2
            object num1 = 1234567890;
            object padding1 = 8;
            object result1 = exchange.numberToBE(num1, padding1);
            Assert(exchange.isBinaryMessage(result1));
            Assert(isEqual(exchange.binaryLength(result1), padding1));
            object expectedBinary1 = exchange.base16ToBinary("00000000499602d2");
            object resultBase64 = exchange.binaryToBase64(result1);
            object expectedBase64 = exchange.binaryToBase64(expectedBinary1);
            Assert(isEqual(resultBase64, expectedBase64), add(add(add("Expected base64: ", expectedBase64), ", got: "), resultBase64));
            // 0 with 1-byte padding => 0x00
            object result2 = exchange.numberToBE(0, 1);
            Assert(exchange.isBinaryMessage(result2));
            Assert(isEqual(exchange.binaryLength(result2), 1));
            object expectedBinary2 = exchange.base16ToBinary("00");
            Assert(isEqual(exchange.binaryToBase64(result2), exchange.binaryToBase64(expectedBinary2)), "zero 1-byte failed");
            // 1 with 1-byte padding => 0x01
            object result3 = exchange.numberToBE(1, 1);
            Assert(exchange.isBinaryMessage(result3));
            Assert(isEqual(exchange.binaryLength(result3), 1));
            object expectedBinary3 = exchange.base16ToBinary("01");
            Assert(isEqual(exchange.binaryToBase64(result3), exchange.binaryToBase64(expectedBinary3)), "one 1-byte failed");
            // 255 with 1-byte padding => 0xFF (max single byte)
            object result4 = exchange.numberToBE(255, 1);
            Assert(exchange.isBinaryMessage(result4));
            Assert(isEqual(exchange.binaryLength(result4), 1));
            object expectedBinary4 = exchange.base16ToBinary("ff");
            Assert(isEqual(exchange.binaryToBase64(result4), exchange.binaryToBase64(expectedBinary4)), "255 1-byte failed");
            // 256 with 2-byte padding => 0x01 0x00
            object result5 = exchange.numberToBE(256, 2);
            Assert(exchange.isBinaryMessage(result5));
            Assert(isEqual(exchange.binaryLength(result5), 2));
            object expectedBinary5 = exchange.base16ToBinary("0100");
            Assert(isEqual(exchange.binaryToBase64(result5), exchange.binaryToBase64(expectedBinary5)), "256 2-byte failed");
            // 1 with 4-byte padding => 0x00 0x00 0x00 0x01
            object result6 = exchange.numberToBE(1, 4);
            Assert(exchange.isBinaryMessage(result6));
            Assert(isEqual(exchange.binaryLength(result6), 4));
            object expectedBinary6 = exchange.base16ToBinary("00000001");
            Assert(isEqual(exchange.binaryToBase64(result6), exchange.binaryToBase64(expectedBinary6)), "1 with 4-byte padding failed");
            // 0 with 8-byte padding => all zeros
            object result7 = exchange.numberToBE(0, 8);
            Assert(exchange.isBinaryMessage(result7));
            Assert(isEqual(exchange.binaryLength(result7), 8));
            object expectedBinary7 = exchange.base16ToBinary("0000000000000000");
            Assert(isEqual(exchange.binaryToBase64(result7), exchange.binaryToBase64(expectedBinary7)), "zero 8-byte failed");
            // 4294967295 (0xFFFFFFFF) with 4-byte padding
            object result8 = exchange.numberToBE(4294967295, 4);
            Assert(exchange.isBinaryMessage(result8));
            Assert(isEqual(exchange.binaryLength(result8), 4));
            object expectedBinary8 = exchange.base16ToBinary("ffffffff");
            Assert(isEqual(exchange.binaryToBase64(result8), exchange.binaryToBase64(expectedBinary8)), "0xFFFFFFFF 4-byte failed");
            // 16909060 (0x01020304) with 4-byte padding
            object result9 = exchange.numberToBE(16909060, 4);
            Assert(exchange.isBinaryMessage(result9));
            Assert(isEqual(exchange.binaryLength(result9), 4));
            object expectedBinary9 = exchange.base16ToBinary("01020304");
            Assert(isEqual(exchange.binaryToBase64(result9), exchange.binaryToBase64(expectedBinary9)), "0x01020304 4-byte failed");
            Assert("GO_SKIP_END");
        }
}